bootstrap.ps1:
$ErrorActionPreference='Stop'; function step{param([string]$m,[scriptblock]$b) Write-Host "[STEP]" $m -ForegroundColor Cyan; & $b }
$DRY=($env:DRY_RUN -eq 'true')
function writeFile([string]$p,[string]$c){$d=Split-Path -Parent $p;if($d -and -not(Test-Path $d)){if($DRY){Write-Host "DRY mkdir $d"}else{New-Item -ItemType Directory -Force -Path $d|Out-Null}}; if($DRY){Write-Host "DRY write $p"}else{Set-Content -LiteralPath $p -Value $c -Encoding UTF8}}
function ensureDir([string]$p){ if(-not(Test-Path $p)){ if($DRY){Write-Host "DRY mkdir $p"} else { New-Item -ItemType Directory -Force -Path $p | Out-Null } } }

step 'Create monorepo folders' { ensureDir 'apps/website'; ensureDir 'apps/crm'; ensureDir 'apps/contractor'; ensureDir 'packages/ui/src'; ensureDir 'packages/tailwind-config'; ensureDir 'packages/eslint-config'; ensureDir 'packages/tsconfig'; ensureDir 'packages/auth' }

step 'Archive current root app (non-destructive)' { if(Test-Path 'src'){ $dest = "_archive/root_app_"+(Get-Date -Format 'yyyyMMddHHmmss'); if($DRY){Write-Host "DRY move src,public,components,lib,prisma -> $dest and copy into apps/website"} else { New-Item -ItemType Directory -Force -Path $dest | Out-Null; foreach($p in @('src','public','components','lib','prisma')){ if(Test-Path $p){ Copy-Item -Recurse -Force $p "apps/website/$p"; Move-Item $p "$dest\$p" -Force } } } } }

step 'Root package.json with workspaces + turbo' {
  $rootPkg = @'{
  "name": "disaster-recovery",
  "private": true,
  "packageManager": "npm@10",
  "workspaces": ["apps/*", "packages/*"],
  "scripts": {
    "dev:website": "turbo dev --filter=website",
    "dev:crm": "turbo dev --filter=crm",
    "dev:contractor": "turbo dev --filter=contractor",
    "build": "turbo build",
    "lint": "turbo lint",
    "type-check": "turbo run type-check"
  },
  "devDependencies": {
    "turbo": "^2.0.0",
    "typescript": "^5.4.0",
    "eslint": "^9.0.0",
    "tailwindcss": "^3.4.0",
    "postcss": "^8.4.0",
    "autoprefixer": "^10.4.0"
  }
}'@
  writeFile 'package.json' $rootPkg
  writeFile 'turbo.json' '{
  "$schema": "https://turbo.build/schema.json",
  "pipeline": {
    "build": { "dependsOn": ["^build"], "outputs": [".next/**", "dist/**"] },
    "dev": {},
    "lint": {},
    "type-check": {}
  }
}' }

step 'Shared tsconfig & eslint config packages' {
  writeFile 'packages/tsconfig/tsconfig.base.json' '{
  "$schema": "https://json.schemastore.org/tsconfig",
  "compilerOptions": {"target": "ES2021", "module": "ESNext", "moduleResolution": "Bundler", "strict": true, "jsx": "preserve", "baseUrl": "."}
}'
  writeFile 'packages/eslint-config/index.js' 'module.exports = { extends: ["next", "next/core-web-vitals" ] };'
}

step 'Tailwind preset (design tokens)' {
  writeFile 'packages/tailwind-config/preset.js' 'const base = {
  theme: {
    extend: {
      colors: {
        brand: { DEFAULT: "#0D3B66", light: "#2D5B86", dark: "#082640" },
        accent: { DEFAULT: "#F4D35E", dark: "#C9A93C" }
      },
      spacing: { 1: "0.25rem", 2: "0.5rem", 3: "0.75rem", 4: "1rem", 6: "1.5rem", 8: "2rem", 12: "3rem" },
      borderRadius: { xl: "1rem", '2xl': "1.25rem" },
      boxShadow: { card: "0 4px 14px rgba(0,0,0,0.08)" }
    }
  }
}; module.exports = base;'
}

step 'Shared UI package (shadcn-like starters)' {
  writeFile 'packages/ui/src/index.ts' 'export * from "./primitives"; export * from "./layout";'
  writeFile 'packages/ui/src/primitives.tsx' "import * as React from 'react'; export const Button=({as:As='button',className='',...p})=> <As className={`inline-flex items-center justify-center rounded-2xl px-4 py-2 font-medium shadow-card hover:opacity-90 ${className}`} {...p}/>; export const Input=(p)=> <input className=\"w-full rounded-xl border px-3 py-2 outline-none focus:ring-2\" {...p}/>; export const Card=({className='',...p})=> <div className={`rounded-2xl bg-white p-4 shadow-card ${className}`} {...p}/>; export const Toast=({children})=> <div role='status' aria-live='polite' className='fixed bottom-4 right-4 rounded-xl bg-black/80 px-3 py-2 text-white'>{children}</div>;"
  writeFile 'packages/ui/src/layout.tsx' "import * as React from 'react'; export const AppShell=({brand='Disaster Recovery',actions,children})=> (<div className='min-h-screen bg-gray-50 text-gray-900'><header className='border-b bg-white'><div className='mx-auto flex max-w-7xl items-center justify-between gap-4 px-4 py-3'><div className='text-lg font-semibold'>{brand}</div><nav className='flex items-center gap-3'>{actions}</nav></div></header><main className='mx-auto max-w-7xl px-4 py-6'>{children}</main></div>); export const AppSwitcher=({items=[]})=> (<div className='flex gap-2'>{items.map(i=> <a key={i.href} href={i.href} className='text-sm underline'>{i.label}</a>)}</div>);"
}

step 'Shared auth stub (choose Auth0/Clerk or NextAuth later)' {
  writeFile 'packages/auth/README.md' '# Auth package\nUse Auth0/Clerk for SSO across subdomains or configure NextAuth cookies with cookie domain .disasterrecovery.com.au.'
  writeFile 'packages/auth/index.ts' 'export const authProvider = process.env.NEXT_PUBLIC_AUTH_PROVIDER || "nextauth";'
}

step 'Scaffold CRM & Contractor apps (Next.js minimal)' {
  writeFile 'apps/crm/package.json' '{"name": "crm", "private": true, "scripts": {"dev": "next dev","build": "next build","start": "next start","lint":"eslint ."}, "dependencies": {"next": "^14.2.0","react": "^18.2.0","react-dom": "^18.2.0"}, "devDependencies":{"@types/react":"^18.2.0","@types/node":"^20.0.0","tailwindcss":"^3.4.0","postcss":"^8.4.0","autoprefixer":"^10.4.0"}}'
  writeFile 'apps/contractor/package.json' '{"name": "contractor", "private": true, "scripts": {"dev": "next dev","build": "next build","start": "next start","lint":"eslint ."}, "dependencies": {"next": "^14.2.0","react": "^18.2.0","react-dom": "^18.2.0"}, "devDependencies": {"@types/react":"^18.2.0","@types/node":"^20.0.0","tailwindcss":"^3.4.0","postcss":"^8.4.0","autoprefixer":"^10.4.0"}}'
  writeFile 'apps/crm/next.config.mjs' 'export default { transpilePackages: ["ui"], experimental:{ serverActions:true } }'
  writeFile 'apps/contractor/next.config.mjs' 'export default { transpilePackages: ["ui"], experimental:{ serverActions:true } }'
  writeFile 'apps/crm/tailwind.config.js' 'module.exports = { presets:[require("@/packages/tailwind-config/preset.js")], content:["./app/**/*.{ts,tsx}","../../packages/ui/src/**/*.{ts,tsx}"] }'
  writeFile 'apps/contractor/tailwind.config.js' 'module.exports = { presets:[require("@/packages/tailwind-config/preset.js")], content:["./app/**/*.{ts,tsx}","../../packages/ui/src/**/*.{ts,tsx}"] }'
  writeFile 'apps/crm/postcss.config.js' 'module.exports={ plugins:{ tailwindcss:{}, autoprefixer:{} } }'
  writeFile 'apps/contractor/postcss.config.js' 'module.exports={ plugins:{ tailwindcss:{}, autoprefixer:{} } }'
  writeFile 'apps/crm/app/layout.tsx' "import '../globals.css'; import {AppShell,AppSwitcher} from 'ui'; export default function RootLayout({children}:{children:React.ReactNode}){ return (<html lang='en'><body><AppShell brand='Disaster Recovery – CRM' actions={<AppSwitcher items={[{label:'Website',href:'https://www.disasterrecovery.com.au'},{label:'Contractor',href:'https://contractors.disasterrecovery.com.au'}]} />}>{children}</AppShell></body></html>) }"
  writeFile 'apps/contractor/app/layout.tsx' "import '../globals.css'; import {AppShell,AppSwitcher} from 'ui'; export default function RootLayout({children}:{children:React.ReactNode}){ return (<html lang='en'><body><AppShell brand='Disaster Recovery – Contractor' actions={<AppSwitcher items={[{label:'Website',href:'https://www.disasterrecovery.com.au'},{label:'CRM',href:'https://crm.disasterrecovery.com.au'}]} />}>{children}</AppShell></body></html>) }"
  writeFile 'apps/crm/app/page.tsx' "import {Card,Button} from 'ui'; export default function Page(){ return (<Card><h1 className='text-2xl font-semibold'>CRM Home</h1><p className='mt-2'>Leads, cases, SLAs.</p><Button className='mt-4'>New Lead</Button></Card>) }"
  writeFile 'apps/contractor/app/page.tsx' "import {Card,Button} from 'ui'; export default function Page(){ return (<Card><h1 className='text-2xl font-semibold'>Contractor Portal</h1><p className='mt-2'>Jobs, compliance, payouts.</p><Button className='mt-4'>View Jobs</Button></Card>) }"
  writeFile 'apps/crm/app/globals.css' '@tailwind base;@tailwind components;@tailwind utilities;'
  writeFile 'apps/contractor/app/globals.css' '@tailwind base;@tailwind components;@tailwind utilities;'
}

step 'Website app tailwind config (use shared tokens)' {
  if(Test-Path 'apps/website'){ writeFile 'apps/website/tailwind.config.js' 'module.exports = { presets:[require("@/packages/tailwind-config/preset.js")], content:["./app/**/*.{ts,tsx}","../../packages/ui/src/**/*.{ts,tsx}"] }' }
}

step 'Root tsconfig path aliases' {
  writeFile 'tsconfig.json' '{ "extends": "./packages/tsconfig/tsconfig.base.json", "compilerOptions": { "paths": { "ui": ["packages/ui/src"], "@/packages/*":["packages/*"] } } }'
}

step 'App README markers' { writeFile 'apps/crm/README.md' '# CRM App\nPrivate staff application.'; writeFile 'apps/contractor/README.md' '# Contractor Portal\nPrivate contractor application.' }

step 'Git hints' { writeFile '.gitignore' "node_modules\n.next\ndist\n.env*\n_archive/\n" }

step 'Summary' { Write-Host 'Scaffold complete. Install deps and run: npm install && npm run dev:website (or :crm / :contractor).' -ForegroundColor Green }
